import styled from "styled-components";

export const TaskWrapper = styled.li`
  list-style-type: none;
  text-align: start;
  display: flex;
  justify-content: space-between;
  padding: 10px;
`

export const TaskText = styled.span`
  font-size: 20px;
  font-family: 'Roboto';
`
export const TaskDell = styled.button`
  border: none;
  background: white
`
